          >
            {slide.leftText}
          </p>
          <div className={cn(isFixed ? "space-y-6" : "space-y-2 sm:space-y-4")}>
            {slide.rightText.map((text, textIdx) => (
              <p
                className={cn(
                  "border-neutral-300 border-b text-neutral-700",
                  isFixed ? "pb-4 text-xl" : "pb-2 text-xs sm:text-sm"
                )}
                key={`right-text-${textIdx}`}
              >
                {text}
              </p>
            ))}
          </div>
        </div>
      </div>
    </>
  );
}

