              )}
            >
              {column.header}
            </h3>

            {/* Column items */}
            <ul
              className={cn(
                "flex flex-col text-neutral-700",
                isFixed
                  ? "gap-2 text-lg"
                  : "gap-1 text-[10px] sm:gap-1.5 sm:text-xs md:gap-2 md:text-sm"
              )}
